# apply-theme.ps1 - dark-theme cleanup for Goals, Account, Insights, health-score card
# Run from App B repo root (paycheck-planner-UPDATED\paycheck-planner).
$ErrorActionPreference = "Stop"
if (-not (Test-Path "package.json") -or -not (Test-Path "app")) {
  Write-Host "ERROR: run from the repo root (folder with package.json)." -ForegroundColor Red; exit 1 }
$files = @{}
$files['app\goals\page.tsx'] = ''
$files['app\components\GoalTracker.tsx'] = ''
$files['app\insights\page.tsx'] = ''
$files['app\components\charts\PieCard.tsx'] = ''
$files['app\account\page.tsx'] = ''
$files['app\components\MfaSetup.tsx'] = ''
$files['app\components\DebtDestructionScore.tsx'] = ''
$files['app\components\DownloadSummaryButton.tsx'] = ''
foreach ($rel in $files.Keys) {
  $full = Join-Path $PWD $rel
  $dir = Split-Path $full -Parent
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  [System.IO.File]::WriteAllBytes($full, [Convert]::FromBase64String($files[$rel]))
  Write-Host "  wrote $rel" -ForegroundColor Green }
Write-Host "Done. 8 files written." -ForegroundColor Cyan